// generar_265_cuidados_calendario_y_analisis_enriquecimiento.js
// CHIQUI Entre Señales — Cuidados en el calendario + Enriquecimiento
// en Análisis
//
// Dos mejoras:
//
// 1) CALENDARIO — al tocar un día, el modal mostraba solo las
//    observaciones (energía, ánimo, apetito...). Ahora también:
//
//    · "Cuidados del día": chips con todo lo marcado ese día —
//      veterinario, medicamento, vacuna, suplemento, baño, cepillado,
//      corte de uñas, limpieza dental, arenero, alimentación, etc.
//      Baño y limpieza dental muestran su tipo cuando existe
//      (ej. "🛁 Baño (dermatológico)", "🦷 Limpieza dental (destartraje)").
//
//    · "🧠 Enriquecimiento": actividades de ese día con su duración
//      (ej. "👃 Juegos de olfato · 15 min") y, en entrenamiento, los
//      trucos practicados ("Practicaron: Sentarse, Dar la pata").
//
//    Así el calendario deja de ser solo un registro de síntomas y pasa
//    a ser la memoria completa del día.
//
// 2) ANÁLISIS — nueva sección "🧠 Enriquecimiento y entrenamiento",
//    justo debajo de Paseos (solo aparece si hay actividades
//    registradas, o sea en perros):
//
//    · Frecuencia: "Actividades de estimulación en 12 de los últimos
//      30 días."
//    · Por actividad: cuántas veces y cuánto tiempo acumulado
//      (ej. "👃 Juegos de olfato — 8 veces · 2h 15m"), ordenado de
//      más a menos frecuente. La primera de la lista ES la actividad
//      favorita, sin necesidad de decirlo.
//    · Trucos practicados: chips con el número de sesiones de cada uno
//      (ej. "Sentarse ×6", "Dar la pata ×4").
//
// SOBRE EL "% DE APRENDIZAJE" que mencionaste: preferí no inventarlo.
// Un porcentaje necesitaría un criterio de "dominado" que hoy no
// existe (¿5 sesiones? ¿10?), y saldría un número que aparenta
// precisión sin tenerla. El conteo de sesiones por truco es el dato
// real y ya cuenta la historia del progreso. Si más adelante quieres
// medir dominio, lo natural sería preguntarlo explícitamente ("¿ya lo
// domina?") en vez de deducirlo — y ahí sí el porcentaje sería honesto.
//
// No hay SQL (usa las tablas del 260 y 262).
//
// Uso:
//   node generar_265_cuidados_calendario_y_analisis_enriquecimiento.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/calendario/page.tsx",
    base64: ""
  },
  {
    ruta: "app/analisis/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 2 archivos escritos. git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
